import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { getComplaintById } from '../services/api';
import '../styles/style.css';

function ComplaintDetail() {
  const { id } = useParams();
  const [complaint, setComplaint] = useState(null);

  useEffect(() => {
    const fetchComplaint = async () => {
      try {
        const token = localStorage.getItem('token');
        const data = await getComplaintById(id, token);
        setComplaint(data);
      } catch (err) {
        alert(err.response?.data?.message || 'Failed to load complaint');
      }
    };
    fetchComplaint();
  }, [id]);

  if (!complaint) return <div>Loading...</div>;

  return (
    <div className="complaint-detail-container">
      <div className="complaint-card">
        <h2>{complaint.title}</h2>
        <p><strong>Description:</strong> {complaint.description}</p>
        <p><strong>Status:</strong> {complaint.status}</p>
        <p><strong>Date:</strong> {new Date(complaint.createdAt).toLocaleDateString()}</p>
      </div>

      {complaint.imageUrl && (
        <div className="complaint-image">
          <img
            className="complaint-thumbnail"
            src={complaint.imageUrl}
            alt="Complaint"
          />
        </div>
      )}

      {complaint.chat && (
        <div className="chat-section">
          <h4>Complaint Chat</h4>
          <ul>
            {complaint.chat.map((msg, index) => (
              <li key={index}><strong>{msg.sender}:</strong> {msg.message}</li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

export default ComplaintDetail;
